SELECT DISTINCT "ID", "SEX", "Diagnosis" 
FROM "Patient" 
WHERE "Thrombosis" = 2;

SELECT COUNT(ID) 
FROM Patient 
WHERE YEAR(Description) = '1997' AND Admission = '-' AND SEX = 'F';

SELECT CAST(SUM(CASE WHEN T1.SEX = 'M' AND T2.UA <= 8.0 THEN 1 ELSE 0 END) AS REAL) / SUM(CASE WHEN T1.SEX = 'F' AND T2.UA <= 6.5 THEN 1 ELSE 0 END) AS Ratio
FROM Patient AS T1
JOIN Laboratory AS T2 ON T1.ID = T2.ID;

SELECT CAST(SUM(CASE WHEN SEX = 'F' THEN 1 ELSE 0 END) AS REAL) * 100 / COUNT(ID) 
FROM Patient 
WHERE STRFTIME('%Y', Birthday) = '1980' AND Diagnosis = 'RA';

SELECT "ID", strftime('%Y', 'now') - strftime('%Y', "Birthday") AS "Age", "Diagnosis"
FROM "Patient"
WHERE "RBC" < 3.5;

SELECT COUNT(DISTINCT "ID") 
FROM "Patient" 
WHERE "CRP" = '+' AND "Description" IS NULL;

SELECT COUNT(DISTINCT "ID") 
FROM "Patient" 
WHERE "SC170" IN ('negative', '0') AND "SEX" = 'F' AND "Symptoms" IS NULL;

